# Given a string s containing just the characters '(', ')', '{', '}', '[' and ']', determine if the input string is valid.

# An input string is valid if:

# Open brackets must be closed by the same type of brackets.
# Open brackets must be closed in the correct order.
# Every close bracket has a corresponding open bracket of the same type.


def isValid(s):
    # This is because can't be just close brackets
    if s[0] == "}" or s[0] == "]" or s[0] == "}":
        return False

    # Use a stack to store the open parentheses
    stack = []
    for parenthesis in s:
        # Check these cases, and add them to the top
        if parenthesis == "(" or parenthesis == "{" or parenthesis == "[":
            stack.append(parenthesis)
        # We do compare if the open bracket exists at the top for every closing
        # bracket, if not, then we return false, because it's not a valid parenthesis, also, we need to check if there is an element on the top
        elif parenthesis == ")":
            if len(stack) == 0:
                return False
            elif stack[-1] == "(":
                stack.pop()
            else:
                return False
        elif parenthesis == "}":
            if len(stack) == 0:
                return False
            elif stack[-1] == "{":
                stack.pop()
            else:
                return False
        elif parenthesis == "]":
            if len(stack) == 0:
                return False
            elif stack[-1] == "[":
                stack.pop()
            else:
                return False

    # If the stack is not empty, it is invalid
    if len(stack) != 0:
        return False
    else:
        return True


